// Extract topic - strip common request prefixes
var topic = userText
  .replace(/^(can you |please |could you |i need you to |i want you to |go ahead and )/i, "")
  .replace(/^(write|create|draft|generate|research|produce|compose)\s+(a |an |me |us |)\s*/i, "")
  .replace(/^(\d{3,5})\s*word\s+/i, "")
  .replace(/^(article|report|white paper|whitepaper|blog post|blog|memo|document|piece|essay|newsletter|paper)\s+(about|on|regarding|for|covering|discussing|analyzing|analysing)\s+/i, "")
  .replace(/\s+(and |then |&)\s*(save|upload|put|store|send)\s+(it\s+)?(to|on|in|into)\s+sharepoint\s*/i, "")
  .replace(/\s+to\s+sharepoint\s*$/i, "")
  .trim();
if (!topic || topic.length < 5) topic = userText.trim();

// Extract word count if mentioned
var wcMatch = userText.match(/(\d{3,5})\s*word/i);
var wordCount = wcMatch ? parseInt(wcMatch[1]) : 1200;

// Call the Research & Write webhook
var body = JSON.stringify({
  topic: topic,
  wordCount: wordCount,
  keywords: "",
  additionalInstructions: ""
});

var resp = await new Promise(function(resolve) {
  var req = https.request({
    hostname: "n8n.dakona.net",
    path: "/webhook/dax/research-write",
    method: "POST",
    headers: { "Content-Type": "application/json", "Content-Length": Buffer.byteLength(body) }
  }, function(res) {
    var data = "";
    res.on("data", function(c) { data += c; });
    res.on("end", function() { resolve(data); });
  });
  req.setTimeout(170000, function() { req.destroy(); resolve(JSON.stringify({error: "Timed out after 170 seconds"})); });
  req.on("error", function(e) { resolve(JSON.stringify({error: e.message})); });
  req.write(body); req.end();
});

var result = {};
try { result = JSON.parse(resp); } catch(e) { return "Error parsing response from document generator"; }

if (result.success) {
  return "Document generated and saved to SharePoint:\n- Topic: " + topic + "\n- File: " + result.fileName + "\n- Sections: " + result.sectionCount + "\n- Words: " + result.actualWordCount + "\n- URL: " + result.webUrl;
}

return "Error generating document: " + (result.error || JSON.stringify(result).substring(0, 200));
